import { useEffect, useState, type ReactNode } from "react";
import { SplitViewLayout } from "@/features/planner/shared/components/SplitViewLayout";
import { PlannerEmptyCanvas } from "@/features/planner/ui/PlannerEmptyCanvas";
import type { CatalogItem } from "@/features/planner/catalog/catalogTypes";

import type { PlannerToolBinding } from "@/features/planner/editor/plannerKeyboardShortcuts";

export interface PlannerCanvasStageProps {
  viewMode: "2d" | "3d" | "split";
  chromeLayerRef: React.RefObject<HTMLDivElement | null>;
  canvasSurfaceRef: React.RefObject<HTMLDivElement | null>;
  dragItem: CatalogItem | null;
  isCatalogOverCanvas: boolean;
  handleCanvasDragOver: (e: React.DragEvent<HTMLDivElement>) => void;
  handleCanvasDrop: (e: React.DragEvent<HTMLDivElement>) => void;
  canvas2D: ReactNode;
  canvas3D: ReactNode;
  shapeCount: number;
  guestMode: boolean;
  applyToolBinding: (binding: PlannerToolBinding) => void;
  setIsTemplateOpen: (open: boolean) => void;
  onQuickLayout?: () => void;
  onUploadFloorPlan?: () => void;
  onClose3D?: () => void;
  plannerChromeHost: ReactNode;
  toolRail?: ReactNode;
  statusBar: ReactNode;
}

export function PlannerCanvasStage({
  viewMode,
  chromeLayerRef,
  canvasSurfaceRef,
  dragItem,
  isCatalogOverCanvas,
  handleCanvasDragOver,
  handleCanvasDrop,
  canvas2D,
  canvas3D,
  shapeCount,
  guestMode,
  applyToolBinding,
  setIsTemplateOpen,
  onQuickLayout,
  onUploadFloorPlan,
  onClose3D,
  plannerChromeHost,
  toolRail,
  statusBar,
}: PlannerCanvasStageProps) {
  const [emptyCanvasDismissed, setEmptyCanvasDismissed] = useState(false);

  useEffect(() => {
    if (shapeCount > 0) {
      setEmptyCanvasDismissed(false);
    }
  }, [shapeCount]);

  return (
    <section className="pw-canvas-stage absolute inset-x-0 top-12 bottom-16 md:static">
      <div className="pw-canvas-stage-inner flex flex-col md:flex-row w-full h-full" style={{ touchAction: "none" }}>
        {toolRail}
        <section className="pw-canvas-area" aria-label="Workspace canvas">
        <div className="pw-canvas-body flex-1 flex flex-col" data-view-mode={viewMode}>
          <div ref={chromeLayerRef} className="pw-canvas-chrome-layer">
            {plannerChromeHost}
          </div>

          <div
            ref={canvasSurfaceRef}
            className="pw-canvas-surface"
            data-catalog-drop={dragItem && isCatalogOverCanvas ? "active" : undefined}
            onDragOver={handleCanvasDragOver}
            onDrop={handleCanvasDrop}
          >
            <div
              className="pw-canvas-engine pw-fabric-container flex h-full min-h-0 w-full flex-col"
              data-testid="planner-2d-canvas"
            >
              <SplitViewLayout
                view={viewMode}
                children2D={canvas2D}
                children3D={canvas3D}
                onClose3D={onClose3D}
              />
            </div>
            {viewMode === "2d" && shapeCount === 0 && !emptyCanvasDismissed ? (
              <PlannerEmptyCanvas
                guestMode={guestMode}
                allowCanvasDragThrough
                onDrawWalls={() => {
                  setEmptyCanvasDismissed(true);
                  applyToolBinding({ toolId: "planner-wall", plannerTool: "wall" });
                }}
                onOpenTemplates={() => setIsTemplateOpen(true)}
                onQuickLayout={onQuickLayout}
                onUploadFloorPlan={onUploadFloorPlan}
              />
            ) : null}
          </div>
        </div>
        {statusBar}
      </section>
      </div>
    </section>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { useLoader } from "@react-three/fiber";
import { useGLTF } from "@react-three/drei";
import { GLTFLoader } from "three/examples/jsm/loaders/GLTFLoader.js";
import type { GLTF } from "three-stdlib";
import { Matrix4, Mesh, type BufferGeometry, type Material } from "three";
import { loadPlannerCatalog } from "@/features/planner/shared/catalog/catalogAdapter";
import type { CatalogItem } from "@/features/planner/shared/catalog/types";

export interface PlannerAssetRecord {
  catalogId: string;
  modelUrl: string | null;
  svgUrl: string | null;
  tint: string | null;
  dimensionsMm: {
    width: number;
    depth: number;
    height: number;
  };
}

export interface LoadedAssetPrimitive {
  key: string;
  geometry: BufferGeometry;
  material: Material;
  localMatrix: Matrix4;
  castShadow: boolean;
  receiveShadow: boolean;
}

export interface LoadedPlannerAsset extends PlannerAssetRecord {
  primitives: LoadedAssetPrimitive[];
}

export interface UseAssetLoaderOptions {
  catalogIds: readonly string[];
  catalogItems?: readonly CatalogItem[] | null;
  loadCatalog?: () => Promise<CatalogItem[]>;
  enabled?: boolean;
}

interface UseAssetLoaderResult {
  assetsByCatalogId: Map<string, LoadedPlannerAsset>;
  catalogById: Map<string, PlannerAssetRecord>;
  isLoadingCatalog: boolean;
  missingCatalogIds: string[];
}

function toAssetRecord(item: CatalogItem): PlannerAssetRecord {
  return {
    catalogId: item.id,
    modelUrl: item.modelUrl ?? null,
    svgUrl: item.thumbnail ?? item.imageUrl ?? null,
    tint: item.color ?? null,
    dimensionsMm: {
      width: item.dimensions.widthMm,
      depth: item.dimensions.depthMm,
      height: item.dimensions.heightMm,
    },
  };
}

function buildCatalogIndex(items: readonly CatalogItem[]): Map<string, PlannerAssetRecord> {
  return new Map(items.map((item) => [item.id, toAssetRecord(item)]));
}

function extractAssetPrimitives(gltf: GLTF): LoadedAssetPrimitive[] {
  gltf.scene.updateMatrixWorld(true);
  const rootInverse = new Matrix4().copy(gltf.scene.matrixWorld).invert();
  const primitives: LoadedAssetPrimitive[] = [];

  gltf.scene.traverse((node: import("three").Object3D) => {
    if (!(node instanceof Mesh) || !node.geometry) {
      return;
    }

    const material = Array.isArray(node.material) ? node.material[0] : node.material;
    if (!material) {
      return;
    }

    primitives.push({
      key: `${node.name || "mesh"}-${primitives.length}`,
      geometry: node.geometry,
      material,
      localMatrix: new Matrix4().multiplyMatrices(rootInverse, node.matrixWorld),
      castShadow: node.castShadow,
      receiveShadow: node.receiveShadow,
    });
  });

  return primitives;
}

export function useAssetLoader({
  catalogIds,
  catalogItems = null,
  loadCatalog = loadPlannerCatalog,
  enabled = true,
}: UseAssetLoaderOptions): UseAssetLoaderResult {
  const [loadedCatalog, setLoadedCatalog] = useState<readonly CatalogItem[] | null>(null);

  useEffect(() => {
    if (!enabled) {
      return;
    }
    if (catalogItems) {
      return;
    }

    let cancelled = false;

    void loadCatalog()
      .then((items) => {
        if (!cancelled) {
          setLoadedCatalog(items);
        }
      })
      .catch(() => {
        if (!cancelled) {
          setLoadedCatalog([]);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [catalogItems, enabled, loadCatalog]);

  const runtimeCatalog = useMemo(
    () => catalogItems ?? loadedCatalog ?? [],
    [catalogItems, loadedCatalog],
  );
  const isLoadingCatalog = !catalogItems && loadedCatalog === null;

  const catalogById = useMemo(
    () => buildCatalogIndex(runtimeCatalog),
    [runtimeCatalog],
  );

  const requestedCatalogIds = useMemo(() => {
    const seen = new Set<string>();
    const ids: string[] = [];

    for (const catalogId of catalogIds) {
      if (!catalogId || seen.has(catalogId)) {
        continue;
      }
      seen.add(catalogId);
      ids.push(catalogId);
    }

    return ids;
  }, [catalogIds]);

  const requestedModelUrls = useMemo(() => {
    const seen = new Set<string>();
    const urls: string[] = [];

    for (const catalogId of requestedCatalogIds) {
      const modelUrl = catalogById.get(catalogId)?.modelUrl;
      if (!modelUrl || seen.has(modelUrl)) {
        continue;
      }
      seen.add(modelUrl);
      urls.push(modelUrl);
    }

    return urls;
  }, [catalogById, requestedCatalogIds]);

  useEffect(() => {
    requestedModelUrls.forEach((modelUrl) => {
      useGLTF.preload(modelUrl);
    });
  }, [requestedModelUrls]);

  const gltfList = useLoader(GLTFLoader, enabled ? requestedModelUrls : []) as unknown as GLTF[];

  const assetsByCatalogId = useMemo(() => {
    const primitivesByUrl = new Map<string, LoadedAssetPrimitive[]>();

    requestedModelUrls.forEach((modelUrl, index) => {
      const gltf = gltfList[index];
      if (!gltf) {
        return;
      }
      primitivesByUrl.set(modelUrl, extractAssetPrimitives(gltf));
    });

    const resolvedAssets = new Map<string, LoadedPlannerAsset>();
    requestedCatalogIds.forEach((catalogId) => {
      const asset = catalogById.get(catalogId);
      if (!asset?.modelUrl) {
        return;
      }

      resolvedAssets.set(catalogId, {
        ...asset,
        primitives: primitivesByUrl.get(asset.modelUrl) ?? [],
      });
    });

    return resolvedAssets;
  }, [catalogById, gltfList, requestedCatalogIds, requestedModelUrls]);

  const missingCatalogIds = useMemo(
    () => requestedCatalogIds.filter((catalogId) => !catalogById.has(catalogId)),
    [catalogById, requestedCatalogIds],
  );

  return {
    assetsByCatalogId,
    catalogById,
    isLoadingCatalog,
    missingCatalogIds,
  };
}

/**
 * Lazy 3D Viewer Module
 * 
 * This module provides lazy loading for the 3D viewer to avoid eager mounting
 * on default planner load. The 3D view is only loaded when explicitly requested.
 */

import { lazy, Suspense } from "react";
import type { ReactNode, ComponentType } from "react";
import type { Open3dProject } from "../model/types";
import styles from "./threeLazyViewer.module.css";

/**
 * Loading fallback component for lazy-loaded 3D viewer.
 */
function ViewerLoadingFallback({ message = "Loading 3D viewer..." }: { message?: string }) {
  return (
    <div className={styles.loading}>
      {message}
    </div>
  );
}

/**
 * Error fallback when 3D viewer fails to load.
 */
function ViewerErrorFallback({
  error,
  onRetry,
}: {
  error: Error | null;
  onRetry?: () => void;
}) {
  return (
    <div className={styles.error}>
      <p>Failed to load 3D viewer</p>
      {error && <p className={styles.errorDetail}>{error.message}</p>}
      {onRetry && (
        <button
          onClick={onRetry}
          className={styles.retryButton}
        >
          Retry
        </button>
      )}
    </div>
  );
}

/**
 * Props for the Lazy3DViewer component.
 */
export interface Lazy3DViewerProps {
  /** The project data to render */
  projectData?: Pick<Open3dProject, "id" | "name" | "floors">;
  /** Optional CSS className */
  className?: string;
  /** Callback when 3D view is ready */
  onReady?: () => void;
  /** Callback when an error occurs */
  onError?: (error: Error) => void;
  /** Loading message */
  loadingMessage?: string;
  /** Enable shadows (default: true) */
  enableShadows?: boolean;
  /** Enable orbit controls (default: true) */
  enableControls?: boolean;
  /** Background color */
  backgroundColor?: string;
}

// Lazy-loaded 3D viewer component
// In production, this would import from a real Three.js component
const Lazy3DViewerInner = lazy(() =>
  import(/* webpackChunkName: "three-viewer" */ "./ThreeViewerInner").then((mod) => ({
    default: mod.ThreeViewerInner,
  })),
);

/**
 * Error boundary state.
 */
interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

/**
 * Error boundary for catching 3D viewer errors.
 */
class ViewerErrorBoundary extends React.Component<
  { children: ReactNode; onError?: (error: Error) => void },
  ErrorBoundaryState
> {
  constructor(props: { children: ReactNode; onError?: (error: Error) => void }) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error): void {
    this.props.onError?.(error);
  }

  render(): ReactNode {
    if (this.state.hasError) {
      return <ViewerErrorFallback error={this.state.error} onRetry={() => this.setState({ hasError: false, error: null })} />;
    }
    return this.props.children;
  }
}

// Need to import React for the class component
import React from "react";

/**
 * Lazy3DViewer - A lazy-loading wrapper for the 3D viewer.
 * 
 * This component does NOT mount on default planner load. It must be
 * explicitly rendered when the user requests 3D view.
 * 
 * Usage:
 * ```tsx
 * import { Lazy3DViewer } from "./three-lazy/Lazy3DViewer";
 * 
 * // Only render when user clicks "View 3D" button
 * {show3DView && <Lazy3DViewer projectData={project} />}
 * ```
 */
export function Lazy3DViewer(props: Lazy3DViewerProps): React.JSX.Element {
  const {
    projectData,
    className,
    onReady,
    onError,
    loadingMessage = "Loading 3D viewer...",
    enableShadows = true,
    enableControls = true,
    backgroundColor = "#ffffff",
  } = props;

  return (
    <div
      className={`${styles.viewerRoot} ${className || ""}`}
      style={{ backgroundColor }}
    >
      <ViewerErrorBoundary onError={onError}>
        <Suspense fallback={<ViewerLoadingFallback message={loadingMessage} />}>
          <Lazy3DViewerInner
            projectData={projectData}
            enableShadows={enableShadows}
            enableControls={enableControls}
            backgroundColor={backgroundColor}
            onReady={onReady}
          />
        </Suspense>
      </ViewerErrorBoundary>
    </div>
  );
}

/**
 * Checks if the browser supports WebGL (required for 3D).
 * @returns True if WebGL is supported
 */
export function isWebGLSupported(): boolean {
  if (typeof window === "undefined" || typeof document === "undefined") return false;

  try {
    const canvas = document.createElement("canvas");
    const gl = canvas.getContext("webgl") || canvas.getContext("experimental-webgl");
    // Check if we got a valid WebGL context (truthy non-null value)
    return gl !== null && gl !== undefined;
  } catch {
    return false;
  }
}

/**
 * Checks if the device has sufficient performance for 3D.
 * @returns True if the device is likely capable
 */
export function isDeviceCapable(): boolean {
  if (typeof window === "undefined" || typeof navigator === "undefined") return false;

  // Check for hardware concurrency (CPUs)
  const cores = navigator.hardwareConcurrency ?? 0;
  if (cores < 2) return false;

  // Check for device memory (if available)
  const memory = (navigator as { deviceMemory?: number }).deviceMemory ?? Infinity;
  if (memory < 2) return false;

  return true;
}

/**
 * Preload check results.
 */
export interface PreloadCheckResult {
  canLoad: boolean;
  reasons: string[];
}

/**
 * Checks if the 3D viewer can be loaded.
 * @returns Preload check result
 */
export function checkCanLoad3D(): PreloadCheckResult {
  const reasons: string[] = [];

  if (!isWebGLSupported()) {
    reasons.push("WebGL is not supported in this browser");
  }

  if (!isDeviceCapable()) {
    reasons.push("Device does not meet minimum requirements");
  }

  return {
    canLoad: reasons.length === 0,
    reasons,
  };
}

