/**
 * Phase 03 Asset Validation
 *
 * Validates asset URLs against an allowed-origin allowlist, checks expiration,
 * and resolves safe URLs or triggers fallback paths.
 *
 * CSP-aligned: only HTTPS URLs from approved origins, plus relative local CDN paths.
 */

// ── Allowed origin allowlist ──

/**
 * Approved origins for catalog asset URLs.
 * Extend this list as CDN domains and image hosting services are added.
 */
const DEFAULT_ALLOWED_ORIGIN_PATTERNS = [
  // R2 / Cloudflare R2
  "pub-[a-z0-9]+\\.r2\\.dev",
  // Local relative paths (no origin — handled separately)
  // Supabase storage
  "[a-z0-9]+\\.supabase\\.co",
  // Common CDN domains (placeholder — configure per deployment)
  "cdn\\.oando\\.co\\.in",
  "assets\\.oando\\.co\\.in",
  "images\\.oando\\.co\\.in",
];

const allowedOriginPatterns = [...DEFAULT_ALLOWED_ORIGIN_PATTERNS];

function compileOriginPattern(pattern: string): RegExp | null {
  try {
    return new RegExp(`^https://${pattern}$`, "i");
  } catch {
    return null;
  }
}

let allowedOriginRegexes = allowedOriginPatterns
  .map(compileOriginPattern)
  .filter((regex): regex is RegExp => regex !== null);

/**
 * Test whether a URL origin matches any pattern in the allowlist.
 */
function originMatchesAllowlist(origin: string): boolean {
  return allowedOriginRegexes.some((regex) => regex.test(origin));
}

// ── URL validation ──

/**
 * Result of asset URL validation.
 */
export interface AssetUrlValidation {
  /** Whether the URL is safe to use */
  valid: boolean;
  /** Sanitized URL (null if invalid) */
  url: string | null;
  /** Reason for rejection, if invalid */
  reason?: string;
}

/**
 * Validate a single asset URL against the origin allowlist and format rules.
 *
 * Rules:
 * - Relative URLs (starting with /) are always valid (local CDN/public path).
 * - HTTPS URLs must match an allowed origin pattern.
 * - HTTP URLs are rejected (insecure).
 * - Non-string or empty values are rejected.
 *
 * Performance target: <10ms per asset.
 */
export function validateAssetUrl(raw: string | undefined | null): AssetUrlValidation {
  if (raw == null || typeof raw !== "string") {
    return { valid: false, url: null, reason: "missing or non-string URL" };
  }

  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    return { valid: false, url: null, reason: "empty URL" };
  }

  // Relative URLs (e.g., /images/chair.svg, ./preview.png) are valid
  if (trimmed.startsWith("/") || trimmed.startsWith("./") || trimmed.startsWith("../")) {
    return { valid: true, url: trimmed };
  }

  // Parse URL to extract scheme and origin
  let parsed: URL;
  try {
    parsed = new URL(trimmed);
  } catch {
    return { valid: false, url: null, reason: `malformed URL: ${trimmed.slice(0, 100)}` };
  }

  // Must be HTTPS
  if (parsed.protocol !== "https:") {
    return { valid: false, url: null, reason: `insecure protocol: ${parsed.protocol}` };
  }

  // Check against allowlist
  if (!originMatchesAllowlist(parsed.origin)) {
    return {
      valid: false,
      url: null,
      reason: `origin not in allowlist: ${parsed.origin}`,
    };
  }

  return { valid: true, url: trimmed };
}

/**
 * Validate multiple asset URLs. Returns validated URLs and a count of rejected ones.
 */
export function validateAssetUrls(
  urls: readonly (string | undefined | null)[],
): { validUrls: string[]; rejectedCount: number } {
  const validUrls: string[] = [];
  let rejectedCount = 0;

  for (const raw of urls) {
    const result = validateAssetUrl(raw);
    if (result.valid && result.url) {
      validUrls.push(result.url);
    } else {
      rejectedCount++;
    }
  }

  return { validUrls, rejectedCount };
}

// ── Asset expiration ──

/**
 * Default TTL for signed URLs: 24 hours.
 */
const DEFAULT_ASSET_TTL_MS = 24 * 60 * 60 * 1000;

/**
 * Check whether an asset URL is expired based on its generation timestamp.
 *
 * Signed URLs from cloud storage typically include an expiration.
 * This is a client-side heuristic — the actual expiration is enforced
 * by the storage provider. If no timestamp is provided, the URL is
 * considered fresh.
 */
export function isAssetUrlExpired(
  generatedAtMs: number | undefined,
  ttlMs: number = DEFAULT_ASSET_TTL_MS,
): boolean {
  if (generatedAtMs == null) return false;
  const now = Date.now();
  return now - generatedAtMs > ttlMs;
}

// ── Asset resolution ──

/**
 * Resolve an asset URL: validate, check expiration, return safe URL or null.
 *
 * Returns the validated URL if:
 * - URL is present and non-empty
 * - URL passes origin allowlist validation
 * - URL is not expired (if timestamp provided)
 *
 * Returns null if any check fails — caller should use fallback geometry.
 */
export function resolveAssetUrl(
  raw: string | undefined | null,
  generatedAtMs?: number,
): string | null {
  const validation = validateAssetUrl(raw);
  if (!validation.valid || !validation.url) return null;

  if (isAssetUrlExpired(generatedAtMs)) return null;

  return validation.url;
}

/**
 * Add an allowed origin pattern to the runtime allowlist.
 * Use for testing or dynamic configuration.
 */
export function addAllowedOrigin(pattern: string): void {
  const normalizedPattern = pattern.trim();
  if (!normalizedPattern) return;

  const compiled = compileOriginPattern(normalizedPattern);
  if (!compiled) return;

  allowedOriginPatterns.push(normalizedPattern);
  allowedOriginRegexes = [...allowedOriginRegexes, compiled];
}

/**
 * Get the current allowlist (for debugging/testing).
 */
export function getAllowedOrigins(): readonly string[] {
  return [...allowedOriginPatterns];
}

/**
 * Phase 03 Catalog Client
 *
 * Client-side catalog management with search, filtering, indexing,
 * LRU caching, cursor-based pagination, and stale-data revalidation.
 *
 * Performance targets:
 * - O(1) lookups via index (byId, bySlug, bySku)
 * - Search p95 <100ms at 1,000 records
 * - Catalog load p95 <500ms for 200 items
 * - Memory: catalog index + cache ≤5MB for 1,000 items
 */

import type {
  Open3dCatalogItem,
  Open3dCatalogIndex,
  Open3dCatalogSearchQuery,
  Open3dCatalogSearchResult,
  Open3dCatalogCategory,
  Open3dRoomTag,
  Open3dStyleTag,
} from "./catalogTypes";
import {
  mapConfiguratorProductToCatalogItem,
  mapPlannerManagedProductToCatalogItem,
  type ConfiguratorProductInput,
  type PlannerManagedProductInput,
} from "./catalogMapping";

// ── LRU Cache ──

interface CacheEntry<T> {
  value: T;
  lastAccess: number;
  age: number; // timestamp when cached
}

const DEFAULT_CACHE_MAX_ITEMS = 5000;
const DEFAULT_CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes
const STALE_REVALIDATION_THRESHOLD_MS = 0.5 * DEFAULT_CACHE_TTL_MS; // 50% of TTL

/**
 * Simple in-memory LRU cache with configurable max items and TTL.
 */
class LRUCache<T> {
  private store = new Map<string, CacheEntry<T>>();
  private maxItems: number;
  private ttlMs: number;
  private staleThresholdMs: number;

  constructor(maxItems = DEFAULT_CACHE_MAX_ITEMS, ttlMs = DEFAULT_CACHE_TTL_MS) {
    this.maxItems = maxItems;
    this.ttlMs = ttlMs;
    this.staleThresholdMs = ttlMs * 0.5;
  }

  get(key: string): { value: T; stale: boolean } | null {
    const entry = this.store.get(key);
    if (!entry) return null;

    const now = Date.now();
    if (now - entry.age > this.ttlMs) {
      this.store.delete(key);
      return null;
    }

    // Update LRU: move to end
    this.store.delete(key);
    entry.lastAccess = now;
    this.store.set(key, entry);

    const stale = now - entry.age > this.staleThresholdMs;
    return { value: entry.value, stale };
  }

  set(key: string, value: T): void {
    // Evict oldest if at capacity
    if (this.store.size >= this.maxItems) {
      const oldestKey = this.store.keys().next().value;
      if (oldestKey !== undefined) {
        this.store.delete(oldestKey);
      }
    }

    const now = Date.now();
    // Remove previous entry if exists (for LRU order)
    this.store.delete(key);
    this.store.set(key, { value, lastAccess: now, age: now });
  }

  has(key: string): boolean {
    return this.get(key) !== null;
  }

  delete(key: string): void {
    this.store.delete(key);
  }

  clear(): void {
    this.store.clear();
  }

  get size(): number {
    return this.store.size;
  }
}

// ── Text tokenization ──

const TOKEN_PATTERN = /[\wÀ-ÿ]+/g;

/**
 * Tokenize text into lowercase normalized tokens for search indexing.
 */
function tokenize(text: string): string[] {
  const tokens: string[] = [];
  const matches = text.toLowerCase().match(TOKEN_PATTERN);
  if (matches) {
    for (const m of matches) {
      if (m.length >= 2) {
        tokens.push(m);
        // Also index 3-char prefixes for fuzzy matching
        if (m.length > 3) {
          for (let i = 3; i <= m.length; i++) {
            tokens.push(m.slice(0, i));
          }
        }
      }
    }
  }
  return tokens;
}

/**
 * Compute search relevance score for a catalog item against a query.
 *
 * Ranking: exact SKU match (100) > exact name match (80) > tag match (50) >
 * description match (30) > fuzzy token match (10 per token).
 */
function computeRelevance(item: Open3dCatalogItem, queryTokens: string[], queryLower: string): number {
  let score = 0;

  // Exact SKU match
  if (item.sku.toLowerCase() === queryLower) {
    score += 100;
  }

  // Exact name match
  if (item.name.toLowerCase() === queryLower) {
    score += 80;
  }

  // Exact slug match
  if (item.slug.toLowerCase() === queryLower) {
    score += 70;
  }

  // Token matching
  const itemTokens = new Set(tokenize(`${item.name} ${item.description} ${item.tags.join(" ")} ${item.sku}`));
  for (const qt of queryTokens) {
    if (itemTokens.has(qt)) {
      // Tag match
      if (item.tags.some((t) => t.toLowerCase() === qt)) {
        score += 50;
      }
      // Name token match
      else if (item.name.toLowerCase().includes(qt)) {
        score += 30;
      }
      // Description match
      else if (item.description.toLowerCase().includes(qt)) {
        score += 15;
      }
      // Fuzzy match
      else {
        score += 10;
      }
    } else {
      // 3-char prefix fuzzy match
      for (const it of itemTokens) {
        if (it.startsWith(qt) || qt.startsWith(it)) {
          score += 5;
          break;
        }
      }
    }
  }

  return score;
}

function compareCatalogItems(a: Open3dCatalogItem, b: Open3dCatalogItem): number {
  return a.name.localeCompare(b.name)
    || a.sku.localeCompare(b.sku)
    || a.id.localeCompare(b.id);
}

function compareNewest(a: Open3dCatalogItem, b: Open3dCatalogItem): number {
  const left = Date.parse(a.provenance.importedAt ?? "");
  const right = Date.parse(b.provenance.importedAt ?? "");
  const safeLeft = Number.isFinite(left) ? left : 0;
  const safeRight = Number.isFinite(right) ? right : 0;
  return (safeRight - safeLeft) || compareCatalogItems(a, b);
}

// ── Catalog Client ──

export type CatalogSource = "standard" | "configurator";

export interface CatalogClientOptions {
  maxCacheItems?: number;
  cacheTtlMs?: number;
  defaultPageSize?: number;
  searchPageSize?: number;
  fetchImpl?: typeof fetch;
  apiBasePath?: string;
}

interface CatalogApiEnvelope {
  items?: unknown[];
  data?: { items?: unknown[] };
}

const DEFAULT_PAGE_SIZE = 50;
const DEFAULT_SEARCH_PAGE_SIZE = 20;

/**
 * Open3dCatalogClient manages the full catalog lifecycle:
 * loading, indexing, search, filtering, caching, and pagination.
 */
export class Open3dCatalogClient {
  private items: Open3dCatalogItem[] = [];
  private index: Open3dCatalogIndex | null = null;
  private tokenizedIndex: Map<string, Set<string>> = new Map(); // Pre-tokenized for search
  private cache: LRUCache<Open3dCatalogSearchResult>;
  private options: Required<Omit<CatalogClientOptions, "fetchImpl">> & { fetchImpl?: typeof fetch };
  private loadedSource: CatalogSource | null = null;
  private loadedAt: number = 0;

  constructor(options: CatalogClientOptions = {}) {
    this.options = {
      maxCacheItems: options.maxCacheItems ?? DEFAULT_CACHE_MAX_ITEMS,
      cacheTtlMs: options.cacheTtlMs ?? DEFAULT_CACHE_TTL_MS,
      defaultPageSize: options.defaultPageSize ?? DEFAULT_PAGE_SIZE,
      searchPageSize: options.searchPageSize ?? DEFAULT_SEARCH_PAGE_SIZE,
      fetchImpl: options.fetchImpl,
      apiBasePath: options.apiBasePath ?? "",
    };
    this.cache = new LRUCache(this.options.maxCacheItems, this.options.cacheTtlMs);
  }

  /**
   * Load catalog from a normalized array of Open3dCatalogItem.
   * Call this after mapping API responses via catalogMapping.
   * Pre-tokenizes all items for O(1) search lookups.
   */
  load(items: Open3dCatalogItem[], source: CatalogSource): void {
    this.items = items;
    this.loadedSource = source;
    this.loadedAt = Date.now();
    this.index = this.buildIndex(items);
    this.cache.clear();
    // Pre-tokenize all items once for search (PLAN-FAIL-012)
    this.tokenizedIndex.clear();
    for (const item of items) {
      const tokens = tokenize(`${item.name} ${item.description} ${item.tags.join(" ")} ${item.sku}`);
      for (const token of tokens) {
        if (!this.tokenizedIndex.has(token)) {
          this.tokenizedIndex.set(token, new Set());
        }
        this.tokenizedIndex.get(token)!.add(item.id);
      }
    }
  }

  /**
   * Fetch, normalize, and load catalog items from the planner catalog API.
   */
  async loadFromApi(source: CatalogSource, limit = 200): Promise<Open3dCatalogItem[]> {
    const fetcher = this.options.fetchImpl ?? globalThis.fetch;
    if (typeof fetcher !== "function") {
      throw new Error("Catalog API loading requires fetch");
    }

    const path = source === "configurator"
      ? "/api/planner/catalog/configurator"
      : "/api/planner/catalog";
    const url = `${this.options.apiBasePath}${path}?limit=${encodeURIComponent(String(limit))}`;
    const response = await fetcher(url);
    if (!response.ok) {
      throw new Error(`Catalog API request failed: ${response.status}`);
    }

    const envelope = await response.json() as CatalogApiEnvelope;
    const rawItems = Array.isArray(envelope.items)
      ? envelope.items
      : Array.isArray(envelope.data?.items)
        ? envelope.data.items
        : [];
    const items = rawItems
      .map((raw) => this.normalizeApiItem(raw, source))
      .filter((item): item is Open3dCatalogItem => item !== null);

    this.load(items, source);
    return items;
  }

  /**
   * Return the loaded catalog items.
   */
  getAll(): Open3dCatalogItem[] {
    return this.items;
  }

  /**
   * O(1) lookup by ID.
   */
  getById(id: string): Open3dCatalogItem | null {
    if (!this.index) return null;
    return this.index.byId.get(id) ?? null;
  }

  /**
   * O(1) lookup by slug.
   */
  getBySlug(slug: string): Open3dCatalogItem | null {
    if (!this.index) return null;
    return this.index.bySlug.get(slug.toLowerCase()) ?? null;
  }

  /**
   * O(1) lookup by SKU.
   */
  getBySku(sku: string): Open3dCatalogItem | null {
    if (!this.index) return null;
    return this.index.bySku.get(sku.toLowerCase()) ?? null;
  }

  /**
   * Get items by category.
   */
  getByCategory(category: Open3dCatalogCategory): Open3dCatalogItem[] {
    if (!this.index) return [];
    return this.index.byCategory.get(category) ?? [];
  }

  /**
   * Get items by room tag.
   */
  getByRoom(room: string): Open3dCatalogItem[] {
    if (!this.index) return [];
    return this.index.byRoom.get(room as never) ?? [];
  }

  /**
   * Get items by style tag.
   */
  getByStyle(style: string): Open3dCatalogItem[] {
    if (!this.index) return [];
    return this.index.byStyle.get(style as never) ?? [];
  }

  /**
   * Search the catalog with faceted queries.
   */
  search(query: Open3dCatalogSearchQuery = {}): Open3dCatalogSearchResult {
    const startedAt = performance.now();

    if (!this.index || this.items.length === 0) {
      return { items: [], totalCount: 0, nextCursor: null, hasMore: false, tookMs: 0 };
    }

    // Generate cache key for deterministic query caching (order-independent)
    const cacheKey = [
      query.text ?? "",
      query.categoryFilter ?? "",
      [...(query.roomFilter ?? [])].sort().join(","),
      [...(query.styleFilter ?? [])].sort().join(","),
      [...(query.materialFilter ?? [])].sort().join(","),
      [...(query.colorFilter ?? [])].sort().join(","),
      [...(query.availabilityFilter ?? [])].sort().join(","),
      [...(query.configurabilityFilter ?? [])].sort().join(","),
      [...(query.mountingFilter ?? [])].sort().join(","),
      [...(query.assetReadinessFilter ?? [])].sort().join(","),
      query.dimensionFilter ? `${query.dimensionFilter.minWidthMm ?? ""}-${query.dimensionFilter.maxWidthMm ?? ""}-${query.dimensionFilter.minDepthMm ?? ""}-${query.dimensionFilter.maxDepthMm ?? ""}-${query.dimensionFilter.minHeightMm ?? ""}-${query.dimensionFilter.maxHeightMm ?? ""}` : "",
      query.sortOrder ?? "",
      query.sortField ?? "",
      query.sortDirection ?? "",
      query.pageSize ?? "",
      query.cursor ?? "",
    ].join("|");

    const cached = this.cache.get(cacheKey);
    if (cached && !cached.stale) {
      return { ...cached.value, tookMs: performance.now() - startedAt };
    }

    // Step 1: Apply filters
    let candidates = this.items;

    // Category filter
    if (query.categoryFilter) {
      candidates = candidates.filter((item) => item.category === query.categoryFilter);
    }

    // Room filter
    const roomFilter = query.roomFilter;
    if (roomFilter && roomFilter.length > 0) {
      candidates = candidates.filter((item) =>
        roomFilter.some((r) => item.roomTags.includes(r)),
      );
    }

    // Style filter
    const styleFilter = query.styleFilter;
    if (styleFilter && styleFilter.length > 0) {
      candidates = candidates.filter((item) =>
        styleFilter.some((s) => item.styleTags.includes(s)),
      );
    }

    // Material filter
    const materialFilter = query.materialFilter;
    if (materialFilter && materialFilter.length > 0) {
      const filters = materialFilter.map((m) => m.toLowerCase());
      candidates = candidates.filter((item) =>
        filters.includes(item.material.normalizedMaterial.toLowerCase()),
      );
    }

    // Color filter
    const colorFilter = query.colorFilter;
    if (colorFilter && colorFilter.length > 0) {
      const filters = colorFilter.map((c) => c.toLowerCase());
      candidates = candidates.filter(
        (item) =>
          item.color && filters.includes(item.color.normalizedFamily.toLowerCase()),
      );
    }

    // Dimension filter
    const dimensionFilter = query.dimensionFilter;
    if (dimensionFilter) {
      const df = dimensionFilter;
      const minW = df.minWidthMm, maxW = df.maxWidthMm;
      const minD = df.minDepthMm, maxD = df.maxDepthMm;
      const minH = df.minHeightMm, maxH = df.maxHeightMm;
      candidates = candidates.filter((i) => {
        const { widthMm, depthMm, heightMm } = i.dimensions;
        return (minW == null || widthMm >= minW)
          && (maxW == null || widthMm <= maxW)
          && (minD == null || depthMm >= minD)
          && (maxD == null || depthMm <= maxD)
          && (minH == null || heightMm >= minH)
          && (maxH == null || heightMm <= maxH);
      });
    }

    // Availability filter
    const availabilityFilter = query.availabilityFilter;
    if (availabilityFilter && availabilityFilter.length > 0) {
      candidates = candidates.filter((item) =>
        availabilityFilter.includes(item.availability),
      );
    }

    const configurabilityFilter = query.configurabilityFilter;
    if (configurabilityFilter && configurabilityFilter.length > 0) {
      candidates = candidates.filter((item) =>
        item.configurability != null && configurabilityFilter.includes(item.configurability),
      );
    }

    const mountingFilter = query.mountingFilter;
    if (mountingFilter && mountingFilter.length > 0) {
      candidates = candidates.filter((item) =>
        (item.mounting ?? ["floor"]).some((mounting) => mountingFilter.includes(mounting)),
      );
    }

    const assetReadinessFilter = query.assetReadinessFilter;
    if (assetReadinessFilter && assetReadinessFilter.length > 0) {
      candidates = candidates.filter((item) =>
        (item.assetReadiness ?? ["ready"]).some((state) => assetReadinessFilter.includes(state)),
      );
    }

    // Step 2: Full-text search (uses pre-tokenized index for performance)
    if (query.text && query.text.trim().length > 0) {
      const queryLower = query.text.trim().toLowerCase();
      const queryTokens = tokenize(query.text);

      // Use pre-tokenized index if available, fallback to per-item tokenization
      if (this.tokenizedIndex.size > 0) {
        const matchingIds = new Set<string>();
        for (const qt of queryTokens) {
          const ids = this.tokenizedIndex.get(qt);
          if (ids) {
            for (const id of ids) matchingIds.add(id);
          }
          // Fuzzy prefix match from index
          for (const [token, idSet] of this.tokenizedIndex) {
            if (token.startsWith(qt) || qt.startsWith(token)) {
              for (const id of idSet) matchingIds.add(id);
            }
          }
        }
        const scored = candidates
          .filter((item) => matchingIds.has(item.id))
          .map((item) => ({ item, score: computeRelevance(item, queryTokens, queryLower) }))
          .sort((a, b) => (b.score - a.score) || compareCatalogItems(a.item, b.item));
        candidates = scored.map(({ item }) => item);
      } else {
        // Fallback: per-item tokenization
        const scored = candidates
          .map((item) => ({ item, score: computeRelevance(item, queryTokens, queryLower) }))
          .filter(({ score }) => score > 0);
        scored.sort((a, b) => (b.score - a.score) || compareCatalogItems(a.item, b.item));
        candidates = scored.map(({ item }) => item);
      }
    }

    // Step 3: Sort
    const sortField = query.sortField ?? (
      query.sortOrder === "name-asc" || query.sortOrder === "name-desc" ? "name"
        : query.sortOrder === "price-asc" || query.sortOrder === "price-desc" ? "price"
          : query.sortOrder === "newest" ? "newest"
            : "relevance"
    );
    const sortDirection = query.sortDirection ?? (
      query.sortOrder === "name-desc" || query.sortOrder === "price-desc" ? "desc" : "asc"
    );

    if (sortField !== "relevance") {
      const sorted = [...candidates];
      switch (sortField) {
        case "name":
          sorted.sort((a, b) => compareCatalogItems(a, b));
          if (sortDirection === "desc") sorted.reverse();
          break;
        case "price":
          sorted.sort((a, b) => ((a.pricing?.price ?? 0) - (b.pricing?.price ?? 0)) || compareCatalogItems(a, b));
          if (sortDirection === "desc") sorted.reverse();
          break;
        case "newest":
          sorted.sort(compareNewest);
          if (sortDirection === "asc") sorted.reverse();
          break;
      }
      candidates = sorted;
    } else if (!query.text) {
      candidates = [...candidates].sort(compareCatalogItems);
    }

    // Step 4: Paginate
    const totalCount = candidates.length;
    const pageSize = query.pageSize ?? (query.text ? this.options.searchPageSize : this.options.defaultPageSize);

    let startIndex = 0;
    if (query.cursor) {
      const decoded = parseInt(query.cursor, 36);
      if (!isNaN(decoded) && decoded >= 0 && decoded < totalCount) {
        startIndex = decoded;
      }
    }

    const pageItems = candidates.slice(startIndex, startIndex + pageSize);
    const nextStart = startIndex + pageSize;
    const hasMore = nextStart < totalCount;
    const nextCursor = hasMore ? nextStart.toString(36) : null;

    const result: Open3dCatalogSearchResult = {
      items: pageItems,
      totalCount,
      nextCursor,
      hasMore,
      tookMs: performance.now() - startedAt,
    };

    // Cache the result
    this.cache.set(cacheKey, result);

    return result;
  }

  /**
   * Check if the catalog is loaded.
   */
  isLoaded(): boolean {
    return this.index !== null && this.items.length > 0;
  }

  /**
   * Get the catalog source.
   */
  getSource(): CatalogSource | null {
    return this.loadedSource;
  }

  /**
   * Return true when loaded API data is past half of the configured TTL and
   * should be refreshed in the background by the UI/runtime boundary.
   */
  shouldRevalidate(now = Date.now()): boolean {
    return this.loadedAt > 0 && now - this.loadedAt > this.options.cacheTtlMs * 0.5;
  }

  /**
   * Invalidate all caches.
   */
  invalidate(): void {
    this.cache.clear();
    this.index = this.items.length > 0 ? this.buildIndex(this.items) : null;
  }

  // ── Private helpers ──

  private buildIndex(items: Open3dCatalogItem[]): Open3dCatalogIndex {
    const byId = new Map<string, Open3dCatalogItem>();
    const bySlug = new Map<string, Open3dCatalogItem>();
    const bySku = new Map<string, Open3dCatalogItem>();
    const byCategory = new Map<Open3dCatalogCategory, Open3dCatalogItem[]>();
    const byTag = new Map<string, Open3dCatalogItem[]>();
    const byRoom = new Map<Open3dRoomTag, Open3dCatalogItem[]>();
    const byStyle = new Map<Open3dStyleTag, Open3dCatalogItem[]>();
    const textIndex = new Map<string, Set<string>>();

    for (const item of items) {
      byId.set(item.id, item);
      bySlug.set(item.slug.toLowerCase(), item);
      bySku.set(item.sku.toLowerCase(), item);

      // Category index
      if (!byCategory.has(item.category)) byCategory.set(item.category, []);
      byCategory.get(item.category)!.push(item);

      // Tag index
      for (const tag of item.tags) {
        const key = tag.toLowerCase();
        if (!byTag.has(key)) byTag.set(key, []);
        byTag.get(key)!.push(item);
      }

      // Room index
      for (const room of item.roomTags) {
        if (!byRoom.has(room)) byRoom.set(room, []);
        byRoom.get(room)!.push(item);
      }

      // Style index
      for (const style of item.styleTags) {
        if (!byStyle.has(style)) byStyle.set(style, []);
        byStyle.get(style)!.push(item);
      }

      // Full-text index
      const tokens = tokenize(`${item.name} ${item.description} ${item.tags.join(" ")} ${item.sku}`);
      for (const token of tokens) {
        if (!textIndex.has(token)) textIndex.set(token, new Set());
        textIndex.get(token)!.add(item.id);
      }
    }

    return {
      byId,
      bySlug,
      bySku,
      byCategory,
      byTag,
      byRoom,
      byStyle,
      textIndex,
      all: items,
      builtAt: Date.now(),
    };
  }

  private normalizeApiItem(raw: unknown, source: CatalogSource): Open3dCatalogItem | null {
    if (this.isOpen3dCatalogItem(raw)) return raw;
    return source === "configurator"
      ? mapConfiguratorProductToCatalogItem(raw as ConfiguratorProductInput)
      : mapPlannerManagedProductToCatalogItem(raw as PlannerManagedProductInput);
  }

  private isOpen3dCatalogItem(raw: unknown): raw is Open3dCatalogItem {
    if (!raw || typeof raw !== "object") return false;
    const item = raw as Partial<Open3dCatalogItem>;
    return typeof item.id === "string"
      && typeof item.slug === "string"
      && typeof item.sku === "string"
      && typeof item.name === "string"
      && typeof item.category === "string"
      && typeof item.subCategory === "string"
      && typeof item.taxonomyPath === "string"
      && typeof item.dimensions?.widthMm === "number"
      && typeof item.dimensions.depthMm === "number"
      && typeof item.dimensions.heightMm === "number"
      && Array.isArray(item.roomTags)
      && Array.isArray(item.styleTags)
      && Array.isArray(item.tags)
      && Array.isArray(item.variants)
      && typeof item.provenance?.source === "string";
  }
}

/**
 * Phase 03 Catalog Mapping
 *
 * Maps OOFPLWeb planner catalog API responses into the canonical
 * Open3dCatalogItem domain model. Preserves all source identity fields
 * (plannerSourceSlug, legacyProductId, categoryId, seriesId) for
 * BOQ/quote/export/AI traceability.
 *
 * Bridges from:
 *   - /api/planner/catalog (planner_managed_products)
 *   - /api/planner/catalog/configurator (configurator_products)
 */

import type {
  Open3dCatalogItem,
  Open3dCatalogCategory,
  Open3dCatalogProvenance,
  Open3dCatalogVariant,
  Open3dAvailabilityStatus,
  Open3dRoomTag,
  Open3dStyleTag,
  Open3dAssetReadiness,
  Open3dMountingContract,
} from "./catalogTypes";
import {
  buildTaxonomyPath,
  buildShortName,
  normalizeMaterial,
  normalizeColor,
  normalizeAssemblyType,
} from "./catalogTaxonomy";
import {
  canonicalDimensionsFromCatalogCm,
  configuratorHeightCmFromMixedUnit,
} from "./unitConversion";

// ── Types for OOFPLWeb API inputs ──

/**
 * Shape of a row from /api/planner/catalog (planner_managed_products).
 * Mirrors PlannerManagedProductRow from site/features/planner/model.
 */
export interface PlannerManagedProductInput {
  id: string;
  legacy_product_id?: string | null;
  slug: string;
  planner_source_slug?: string;
  name: string;
  description?: string;
  category?: string;
  category_id?: string;
  category_name?: string;
  series_id?: string;
  series_name?: string;
  price?: number;
  flagship_image?: string;
  images?: string[];
  specs?: Record<string, unknown>;
  metadata?: Record<string, unknown>;
  active?: boolean;
  created_by?: string | null;
  created_at?: string;
  updated_at?: string;
}

/**
 * Shape of a product from /api/planner/catalog/configurator.
 * Mirrors Product from site/lib/catalog/types.ts.
 */
export interface ConfiguratorProductInput {
  id: string;
  slug: string;
  name: string;
  category_id: string;
  family?: string;
  brandName?: string;
  description?: string;
  thumbnailUrl?: string;
  model3dUrl?: string;
  sizingType?: "parametric" | "discrete" | "fixed";
  workstation?: {
    shape?: string;
    lengthOptions?: number[];
    depthOptions?: number[];
    seaterOptions?: number[];
    heightMm?: number;
    sharing?: string;
  };
  sizeOptions?: Array<{ dim: { L: number; D: number; H?: number } }>;
  defaultFootprint?: { L: number; D: number; H?: number };
  specs?: {
    materials?: string[];
    dimensions?: string;
    features?: string[];
  };
}

// ── Category mapping ──

/**
 * Map OOFPLWeb admin/workspace category strings to canonical Open3dCatalogCategory.
 * Based on the existing mapAdminCategoryToWorkspace logic but extended to canonical types.
 */
export function mapAdminCategoryToCanonical(
  category: string,
  subcategory?: string | null,
): Open3dCatalogCategory {
  const blob = `${category} ${subcategory ?? ""}`.toLowerCase();
  if (blob.includes("desk") || blob.includes("workstation") || blob.includes("bench")) return "Furniture";
  if (blob.includes("room") || blob.includes("booth") || blob.includes("pod") || blob.includes("meeting")) return "Furniture";
  if (blob.includes("storage") || blob.includes("locker") || blob.includes("cabinet") || blob.includes("wardrobe")) return "Furniture";
  if (blob.includes("chair") || blob.includes("seat") || blob.includes("stool")) return "Furniture";
  if (blob.includes("table")) return "Furniture";
  if (blob.includes("sofa") || blob.includes("sectional") || blob.includes("loveseat")) return "Furniture";
  if (blob.includes("bed")) return "Furniture";
  if (blob.includes("light") || blob.includes("lamp") || blob.includes("chandelier")) return "Lighting";
  if (blob.includes("rug") || blob.includes("plant") || blob.includes("curtain") || blob.includes("mirror") || blob.includes("art")) return "Decor";
  if (blob.includes("outdoor") || blob.includes("patio") || blob.includes("garden") || blob.includes("bbq")) return "Outdoor";
  if (blob.includes("zone") || blob.includes("infra") || blob.includes("wifi") || blob.includes("display") || blob.includes("electrical") || blob.includes("plumbing")) return "Symbols";
  if (blob.includes("kitchen") || blob.includes("dining") || blob.includes("cook")) return "Kitchen & Dining";
  if (blob.includes("textile") || blob.includes("duvet") || blob.includes("pillow") || blob.includes("throw")) return "Bedding & Textiles";
  return "Furniture";
}

/**
 * Infer room tags from category and subcategory strings.
 */
export function inferRoomTags(category: string, subcategory?: string | null): Open3dRoomTag[] {
  const blob = `${category} ${subcategory ?? ""}`.toLowerCase();
  const tags: Open3dRoomTag[] = [];
  if (blob.includes("living")) tags.push("Living Room");
  if (blob.includes("bedroom")) tags.push("Bedroom");
  if (blob.includes("kitchen")) tags.push("Kitchen");
  if (blob.includes("bathroom")) tags.push("Bathroom");
  if (blob.includes("office") || blob.includes("workstation") || blob.includes("desk")) tags.push("Office");
  if (blob.includes("dining")) tags.push("Dining");
  if (blob.includes("outdoor") || blob.includes("patio") || blob.includes("garden")) tags.push("Outdoor");
  if (blob.includes("garage")) tags.push("Garage");
  if (blob.includes("utility")) tags.push("Utility");
  if (blob.includes("kids") || blob.includes("nursery") || blob.includes("children")) tags.push("Kids & Nursery");
  return tags.length > 0 ? tags : ["Office"];
}

/**
 * Infer style tags from product name and description.
 * Simplified heuristic — production would use ML-based tagging (Wayfair approach).
 */
export function inferStyleTags(name: string, description?: string): Open3dStyleTag[] {
  const blob = `${name} ${description ?? ""}`.toLowerCase();
  const tags: Open3dStyleTag[] = [];
  if (blob.includes("modern") || blob.includes("contemporary")) tags.push("Modern");
  if (blob.includes("scandinavian") || blob.includes("scandi") || blob.includes("nordic")) tags.push("Scandinavian");
  if (blob.includes("industrial")) tags.push("Industrial");
  if (blob.includes("traditional") || blob.includes("classic")) tags.push("Traditional");
  if (blob.includes("coastal")) tags.push("Coastal");
  if (blob.includes("boho") || blob.includes("bohemian")) tags.push("Boho");
  if (blob.includes("mid-century") || blob.includes("midcentury")) tags.push("Mid-Century");
  if (blob.includes("minimalist") || blob.includes("minimal")) tags.push("Minimalist");
  if (blob.includes("rustic")) tags.push("Rustic");
  return tags.length > 0 ? tags : ["Modern"];
}

/**
 * Resolve subcategory from category data.
 */
export function resolveSubCategory(
  category: string,
  seriesName?: string | null,
  family?: string | null,
): string {
  if (seriesName && seriesName.trim().length > 0) return seriesName.trim();
  if (family && family.trim().length > 0) return family.trim();
  const normalized = category.trim().toLowerCase();
  if (normalized.includes("desk") || normalized.includes("workstation")) return "Desks";
  if (normalized.includes("sofa") || normalized.includes("sectional")) return "Sofas & Sectionals";
  if (normalized.includes("chair")) return "Chairs";
  if (normalized.includes("table")) return "Tables";
  if (normalized.includes("storage") || normalized.includes("wardrobe") || normalized.includes("cabinet")) return "Storage";
  if (normalized.includes("bed")) return "Beds";
  if (normalized.includes("light")) return "Lighting";
  return category.trim();
}

/**
 * Resolve availability status from product data.
 */
export function resolveAvailabilityStatus(input: {
  active?: boolean;
  visible?: boolean;
  plannerVisible?: boolean;
}): Open3dAvailabilityStatus {
  if (input.active === false || input.visible === false || input.plannerVisible === false) {
    return "discontinued";
  }
  return "in-stock";
}

function resolveMountingContract(category: Open3dCatalogCategory, subCategory: string): Open3dMountingContract[] {
  const blob = `${category} ${subCategory}`.toLowerCase();
  if (blob.includes("ceiling")) return ["ceiling"];
  if (blob.includes("wall") || blob.includes("mirror") || blob.includes("art") || blob.includes("sconce")) return ["wall"];
  if (category === "Lighting" && blob.includes("pendant")) return ["ceiling"];
  if (category === "Symbols") return ["wall", "ceiling", "floor"];
  return ["floor"];
}

function resolveAssetReadiness(params: { imageUrl?: string; meshUrl?: string; symbolOnly?: boolean }): Open3dAssetReadiness[] {
  const readiness: Open3dAssetReadiness[] = [];
  if (!params.imageUrl) readiness.push("missing-image");
  if (!params.symbolOnly && !params.meshUrl) readiness.push("missing-mesh");
  return readiness.length > 0 ? readiness : ["ready"];
}

// ── Mapping functions ──

/**
 * Map a planner managed product row to a canonical Open3dCatalogItem.
 */
export function mapPlannerManagedProductToCatalogItem(
  input: PlannerManagedProductInput,
): Open3dCatalogItem | null {
  if (!input.id || !input.name) return null;

  const specs = input.specs ?? {};
  const widthCm = Number(specs.widthMm ?? specs.width_mm ?? 0);
  const depthCm = Number(specs.depthMm ?? specs.depth_mm ?? 0);
  // NAMING DEBT: specs.heightMm stores centimetres despite the "Mm" suffix.
  // This matches the OOFPLWeb planner_managed_products column convention.
  // See unitConversion.ts: canonicalMmFromCatalogCm / configuratorHeightCmFromMixedUnit.
  const heightCm = Number(specs.heightMm ?? specs.height_mm ?? 75);
  if (!widthCm || !depthCm) return null;

  const category = mapAdminCategoryToCanonical(input.category ?? "Office", input.series_name);
  const subCategory = resolveSubCategory(input.category ?? "Office", input.series_name);
  const taxonomyPath = buildTaxonomyPath(category, subCategory);
  const dimensions = canonicalDimensionsFromCatalogCm({
    widthCm,
    depthCm,
    heightCm,
    weightKg: undefined,
  });
  const materialName = typeof specs.material === "string" ? specs.material : "Admin catalog";
  const material = normalizeMaterial(materialName);

  const name = input.name.trim();
  const description = input.description ?? `${input.category_name ?? ""} · ${input.series_name ?? ""}`;

  const provenance: Open3dCatalogProvenance = {
    source: "planner_managed_products",
    legacyProductId: input.legacy_product_id ?? undefined,
    plannerSourceSlug: input.planner_source_slug ?? undefined,
    sourceCategoryId: input.category_id ?? undefined,
    sourceSeriesId: input.series_id ?? undefined,
    importedAt: new Date().toISOString(),
  };

  const item: Open3dCatalogItem = {
    id: input.id,
    slug: input.slug || input.id,
    sku: input.slug || input.id,
    name,
    shortName: buildShortName(name),
    description,
    category,
    subCategory,
    taxonomyPath,
    dimensions,
    displayUnit: "cm",
    assets: {
      previewImageUrl: input.flagship_image || (input.images?.[0]) || undefined,
      imageUrls: input.images ?? [],
      meshUrl: undefined,
    },
    material,
    roomTags: inferRoomTags(input.category ?? "Office", input.series_name),
    styleTags: inferStyleTags(name, description),
    tags: [
      "managed",
      input.category ?? "",
      input.series_name ?? "",
      material.normalizedMaterial,
    ].filter(Boolean),
    availability: resolveAvailabilityStatus({ active: input.active }),
    assemblyType: normalizeAssemblyType("partial"),
    configurability: "fixed",
    mounting: resolveMountingContract(category, subCategory),
    assetReadiness: resolveAssetReadiness({ imageUrl: input.flagship_image || input.images?.[0] }),
    flatPack: false,
    variants: [],
    provenance,
    symbolOnly: false,
  };

  return item;
}

/**
 * Map a configurator product to a canonical Open3dCatalogItem.
 * Only call this if configurator products are currently used in the planner.
 */
export function mapConfiguratorProductToCatalogItem(
  input: ConfiguratorProductInput,
): Open3dCatalogItem | null {
  if (!input.slug?.trim() || !input.name?.trim()) return null;

  // Resolve dimensions
  let widthCm = 0;
  let depthCm = 0;
  let heightCm = 75;

  if (input.sizingType === "parametric" && input.workstation) {
    const ws = input.workstation;
    const validLengths = (ws.lengthOptions ?? []).filter((v) => Number.isFinite(v) && v > 0);
    const validDepths = (ws.depthOptions ?? []).filter((v) => Number.isFinite(v) && v > 0);
    const validSeaters = (ws.seaterOptions ?? []).filter((v) => Number.isFinite(v) && v > 0);
    if (validLengths.length > 0 && validDepths.length > 0 && validSeaters.length > 0) {
      const minLen = Math.min(...validLengths);
      const minDep = Math.min(...validDepths);
      const minSeaters = Math.min(...validSeaters);
      widthCm = ws.shape === "l-shape" ? minLen : minSeaters * minLen;
      depthCm = ws.sharing === "sharing" ? minDep * 2 : minDep;
      heightCm = configuratorHeightCmFromMixedUnit(ws.heightMm);
    }
  } else if (input.sizingType === "discrete" && (input.sizeOptions?.length ?? 0) > 0) {
    let bestArea = Number.POSITIVE_INFINITY;
    for (const opt of input.sizeOptions ?? []) {
      const area = opt.dim.L * opt.dim.D;
      if (area > 0 && area < bestArea) {
        bestArea = area;
        widthCm = opt.dim.L;
        depthCm = opt.dim.D;
        heightCm = configuratorHeightCmFromMixedUnit(opt.dim.H);
      }
    }
  } else if (input.defaultFootprint?.L && input.defaultFootprint?.D) {
    widthCm = input.defaultFootprint.L;
    depthCm = input.defaultFootprint.D;
    heightCm = configuratorHeightCmFromMixedUnit(input.defaultFootprint.H);
  }

  if (!widthCm || !depthCm) return null;

  const category = mapAdminCategoryToCanonical(input.category_id, input.family);
  const subCategory = resolveSubCategory(input.category_id, null, input.family);
  const taxonomyPath = buildTaxonomyPath(category, subCategory);
  const dimensions = canonicalDimensionsFromCatalogCm({
    widthCm,
    depthCm,
    heightCm,
  });

  const name = input.name.trim();
  const description = input.description ?? "";
  const materialName = input.specs?.materials?.[0] ?? "Configurator";
  const material = normalizeMaterial(materialName);

  const provenance: Open3dCatalogProvenance = {
    source: "configurator_products",
    sourceCategoryId: input.category_id,
    importedAt: new Date().toISOString(),
  };

  // Build a master variant
  const masterVariant: Open3dCatalogVariant = {
    variantId: `${input.slug}-master`,
    sku: input.slug,
    parentProductId: input.slug,
    label: name,
    variantAttributes: {},
    dimensions,
    imageUrl: input.thumbnailUrl,
    meshUrl: input.model3dUrl,
    availability: "in-stock",
  };

  const seatCount =
    input.sizingType === "parametric"
      ? (() => {
        const opts = input.workstation?.seaterOptions ?? [];
        const valid = opts.filter((v) => v > 0);
        return valid.length > 0 ? Math.min(...valid) : undefined;
      })()
      : undefined;

  const item: Open3dCatalogItem = {
    id: input.slug,
    slug: input.slug,
    sku: input.slug,
    name,
    shortName: buildShortName(name),
    description,
    category,
    subCategory,
    taxonomyPath,
    dimensions,
    displayUnit: "cm",
    assets: {
      previewImageUrl: input.thumbnailUrl,
      imageUrls: input.thumbnailUrl ? [input.thumbnailUrl] : [],
      meshUrl: input.model3dUrl,
    },
    material,
    roomTags: inferRoomTags(input.category_id, input.family),
    styleTags: inferStyleTags(name, description),
    tags: [
      "configurator",
      input.category_id,
      input.family ?? "",
      material.normalizedMaterial,
    ].filter(Boolean),
    availability: "in-stock",
    assemblyType: normalizeAssemblyType("fully-assembled"),
    configurability: input.sizingType === "parametric" ? "configurable" : "fixed",
    mounting: resolveMountingContract(category, subCategory),
    assetReadiness: resolveAssetReadiness({
      imageUrl: input.thumbnailUrl,
      meshUrl: input.model3dUrl,
    }),
    flatPack: false,
    seatCount,
    variants: [masterVariant],
    provenance,
    symbolOnly: false,
  };

  return item;
}

/**
 * Phase 03A Inventory Index
 *
 * Fast search with normalized terms, synonyms, tags, SKU lookup,
 * typo tolerance, zero-result recovery, and deterministic ranking.
 *
 * Performance: search p95 <100ms at 1K records.
 */

import type {
  Open3dAvailabilityStatus,
  Open3dAssetReadiness,
  Open3dCatalogCategory,
  Open3dConfigurability,
  Open3dCatalogItem,
  Open3dMountingContract,
  Open3dRoomTag,
  Open3dStyleTag,
} from "../catalogTypes";

// ── Synonym map ──

/** Common furniture synonym mappings for search expansion */
const SYNONYM_MAP: Record<string, string[]> = {
  "couch": ["sofa", "loveseat", "sectional"],
  "sofa": ["couch", "loveseat", "settee"],
  "desk": ["workstation", "table", "writing-desk", "computer-desk"],
  "chair": ["seat", "stool", "armchair", "seating"],
  "table": ["desk", "surface", "counter"],
  "storage": ["cabinet", "cupboard", "wardrobe", "closet", "shelf"],
  "bed": ["mattress", "bunk", "cot", "bedframe"],
  "lamp": ["light", "lighting", "luminaire", "fixture"],
  "light": ["lamp", "fixture", "luminaire"],
  "rug": ["carpet", "mat", "floor-covering"],
  "plant": ["greenery", "foliage", "tree"],
  "mirror": ["glass", "reflective"],
  "small": ["compact", "tiny", "mini"],
  "large": ["big", "spacious", "oversized", "xl"],
  "office": ["work", "workplace", "business", "corporate"],
  "home": ["house", "residential", "domestic"],
};

/** Expand a token into synonyms for broader search matching */
function expandSynonyms(token: string): string[] {
  const result: string[] = [token];
  const synonyms = SYNONYM_MAP[token];
  if (synonyms) {
    result.push(...synonyms);
  }
  return result;
}

// ── Tokenization ──

const TOKEN_PATTERN = /[\wÀ-ÿ]+/g;

function tokenize(text: string): string[] {
  const tokens: string[] = [];
  const matches = text.toLowerCase().match(TOKEN_PATTERN);
  if (matches) {
    for (const m of matches) {
      if (m.length >= 2) {
        tokens.push(m);
        // Prefix tokens for typo tolerance (3-char minimum)
        if (m.length > 3) {
          for (let i = 3; i <= m.length; i++) {
            tokens.push(m.slice(0, i));
          }
        }
      }
    }
  }
  return tokens;
}

// ── Relevance scoring ──

interface ScoredItem {
  item: Open3dCatalogItem;
  score: number;
}

function compareCatalogItems(a: Open3dCatalogItem, b: Open3dCatalogItem): number {
  return a.name.localeCompare(b.name)
    || a.sku.localeCompare(b.sku)
    || a.id.localeCompare(b.id);
}

function compareScoredItems(a: ScoredItem, b: ScoredItem): number {
  return (b.score - a.score) || compareCatalogItems(a.item, b.item);
}

/**
 * Compute relevance score with deterministic tie-breaking.
 *
 * Accepts pre-tokenized item tokens (built once during load()) to avoid
 * per-call tokenize() allocations in the search hot path (PLAN-FAIL-012).
 *
 * Ranking priority:
 * 1. Exact SKU match: 100
 * 2. Exact name match: 80
 * 3. Exact slug match: 70
 * 4. Tag match: 50 per tag
 * 5. Name token match: 30 per token
 * 6. Description match: 15 per token
 * 7. Fuzzy prefix match: 5 per token
 * 8. Synonym match: 25 per synonym token
 */
function scoreItem(
  item: Open3dCatalogItem,
  preTokenized: string[],
  queryTokens: string[],
  queryLower: string,
): number {
  let score = 0;

  if (item.sku.toLowerCase() === queryLower) score += 100;
  if (item.name.toLowerCase() === queryLower) score += 80;
  if (item.slug.toLowerCase() === queryLower) score += 70;

  const itemTokens = preTokenized;

  // Expand query with synonyms
  const allQueryTokens = new Set<string>();
  for (const qt of queryTokens) {
    for (const syn of expandSynonyms(qt)) {
      allQueryTokens.add(syn);
    }
  }

  for (const qt of allQueryTokens) {
    if (itemTokens.includes(qt)) {
      if (item.tags.some((t) => t.toLowerCase() === qt)) score += 50;
      else if (item.name.toLowerCase().includes(qt)) score += 30;
      else if (item.description.toLowerCase().includes(qt)) score += 15;
      else if (SYNONYM_MAP[queryTokens[0]]?.includes(qt)) score += 25;
      else score += 10;
    } else {
      // Fuzzy prefix match
      for (const it of itemTokens) {
        if (it.startsWith(qt) || qt.startsWith(it)) {
          score += 5;
          break;
        }
      }
    }
  }

  return score;
}

// ── Typo tolerance ──

/**
 * Simple typo tolerance: generates near-miss tokens by single-character edits.
 * Only applied for queries ≥ 4 characters to avoid overwhelming results.
 */
function generateTypoVariants(token: string): string[] {
  if (token.length < 4) return [];
  const variants: string[] = [];
  // Character swap (adjacent)
  for (let i = 0; i < token.length - 1; i++) {
    const chars = token.split("");
    [chars[i], chars[i + 1]] = [chars[i + 1], chars[i]];
    variants.push(chars.join(""));
  }
  return variants.slice(0, 3); // Limit to 3 variants
}

// ── Search engine ──

export interface InventorySearchOptions {
  /** Max results per page */
  pageSize?: number;
  /** Minimum relevance score to include in results */
  minScore?: number;
  /** Whether to use typo tolerance */
  typoTolerance?: boolean;
  /** Optional category filter applied before ranking */
  category?: Open3dCatalogCategory;
  /** Optional room filter. Matches items containing at least one selected room. */
  roomTags?: Open3dRoomTag[];
  /** Optional style filter. Matches items containing at least one selected style. */
  styleTags?: Open3dStyleTag[];
  /** Optional material filter using normalized material values. */
  material?: string[];
  /** Optional availability filter. */
  availability?: Open3dAvailabilityStatus[];
  /** Optional configurability filter. */
  configurability?: Open3dConfigurability[];
  /** Optional mounting/anchoring filter. */
  mounting?: Open3dMountingContract[];
  /** Optional asset-readiness filter for degraded-state recovery. */
  assetReadiness?: Open3dAssetReadiness[];
  /** Optional dimension range filter in millimetres. */
  dimensionFilter?: {
    /** Minimum width in mm */
    minWidthMm?: number;
    /** Maximum width in mm */
    maxWidthMm?: number;
    /** Minimum depth in mm */
    minDepthMm?: number;
    /** Maximum depth in mm */
    maxDepthMm?: number;
    /** Minimum height in mm */
    minHeightMm?: number;
    /** Maximum height in mm */
    maxHeightMm?: number;
  };
}

export interface InventorySearchResult {
  items: Open3dCatalogItem[];
  totalCount: number;
  /** Original query (for zero-result recovery) */
  query: string;
  /** Whether the search was relaxed due to zero results */
  relaxed: boolean;
  /** Suggested correction if typo detected */
  suggestedCorrection?: string;
}

/**
 * Inventory search engine with synonyms, typo tolerance, and zero-result recovery.
 */
export class InventorySearchIndex {
  private items: Open3dCatalogItem[] = [];
  /**
   * Pre-tokenized item corpus, keyed by item ID.
   * Built once in load() so scoreItem() never calls tokenize() at query time.
   * Fixes PLAN-FAIL-012: per-item tokenization in the hot scoring path.
   */
  private itemTokenCache = new Map<string, string[]>();

  load(items: Open3dCatalogItem[]): void {
    this.items = [...items].sort(compareCatalogItems);
    // Pre-tokenize all items once so search scoring is allocation-free per query.
    this.itemTokenCache.clear();
    for (const item of this.items) {
      this.itemTokenCache.set(
        item.id,
        tokenize(`${item.name} ${item.description} ${item.tags.join(" ")} ${item.sku}`),
      );
    }
  }

  private filterItems(options: InventorySearchOptions): Open3dCatalogItem[] {
    const materialFilter = new Set((options.material ?? []).map((value) => value.toLowerCase()));
    const roomFilter = new Set(options.roomTags ?? []);
    const styleFilter = new Set(options.styleTags ?? []);
    const availabilityFilter = new Set(options.availability ?? []);
    const configurabilityFilter = new Set(options.configurability ?? []);
    const mountingFilter = new Set(options.mounting ?? []);
    const assetReadinessFilter = new Set(options.assetReadiness ?? []);
    const dim = options.dimensionFilter;

    return this.items.filter((item) => {
      if (options.category && item.category !== options.category) return false;
      if (roomFilter.size > 0 && !item.roomTags.some((tag) => roomFilter.has(tag))) return false;
      if (styleFilter.size > 0 && !item.styleTags.some((tag) => styleFilter.has(tag))) return false;
      if (materialFilter.size > 0 && !materialFilter.has(item.material.normalizedMaterial.toLowerCase())) return false;
      if (availabilityFilter.size > 0 && !availabilityFilter.has(item.availability)) return false;
      if (configurabilityFilter.size > 0 && (item.configurability == null || !configurabilityFilter.has(item.configurability))) return false;
      if (mountingFilter.size > 0 && !(item.mounting ?? ["floor"]).some((mounting) => mountingFilter.has(mounting))) return false;
      if (assetReadinessFilter.size > 0 && !(item.assetReadiness ?? ["ready"]).some((state) => assetReadinessFilter.has(state))) return false;
      // Dimension range filter
      if (dim) {
        const { widthMm, depthMm, heightMm } = item.dimensions;
        if (dim.minWidthMm != null && widthMm < dim.minWidthMm) return false;
        if (dim.maxWidthMm != null && widthMm > dim.maxWidthMm) return false;
        if (dim.minDepthMm != null && depthMm < dim.minDepthMm) return false;
        if (dim.maxDepthMm != null && depthMm > dim.maxDepthMm) return false;
        if (dim.minHeightMm != null && heightMm < dim.minHeightMm) return false;
        if (dim.maxHeightMm != null && heightMm > dim.maxHeightMm) return false;
      }
      return true;
    });
  }

  /**
   * Search with synonym expansion, ranking, and typo tolerance.
   */
  search(query: string, options: InventorySearchOptions = {}): InventorySearchResult {
    const { pageSize = 20, minScore = 1, typoTolerance = true } = options;
    const candidates = this.filterItems(options);

    if (!query || query.trim().length === 0) {
      return { items: candidates.slice(0, pageSize), totalCount: candidates.length, query: "", relaxed: false };
    }

    const queryLower = query.trim().toLowerCase();
    const queryTokens = tokenize(query);

    // Primary search — uses pre-tokenized cache to avoid per-item tokenize() calls.
    let scored = candidates
      .map((item) => ({
        item,
        score: scoreItem(item, this.itemTokenCache.get(item.id) ?? [], queryTokens, queryLower),
      }))
      .filter((s) => s.score >= minScore)
      .sort(compareScoredItems);

    // Typo tolerance for zero results
    let relaxed = false;
    let suggestedCorrection: string | undefined;

    if (scored.length === 0 && typoTolerance) {
      const typoVariants: string[] = [];
      for (const token of queryTokens) {
        typoVariants.push(...generateTypoVariants(token));
      }

      if (typoVariants.length > 0) {
        const typoTokens = tokenize(typoVariants.join(" "));
        scored = candidates
          .map((item) => ({
            item,
            score: scoreItem(item, this.itemTokenCache.get(item.id) ?? [], typoTokens, queryLower),
          }))
          .filter((s) => s.score >= 1)
          .sort(compareScoredItems);

        if (scored.length > 0) {
          relaxed = true;
          suggestedCorrection = typoVariants[0];
        }
      }
    }
    // compareScoredItems already provides deterministic tie-breaking via name/SKU/ID.

    return {
      items: scored.slice(0, pageSize).map((s) => s.item),
      totalCount: scored.length,
      query,
      relaxed,
      suggestedCorrection,
    };
  }

  /**
   * Auto-complete suggestions for a partial query.
   */
  suggest(query: string, limit = 5): string[] {
    if (!query || query.trim().length < 2) return [];
    const queryLower = query.trim().toLowerCase();
    const suggestions = new Set<string>();

    for (const item of this.items) {
      if (item.name.toLowerCase().includes(queryLower)) {
        suggestions.add(item.name);
      }
      for (const tag of item.tags) {
        if (tag.toLowerCase().includes(queryLower)) {
          suggestions.add(tag);
        }
      }
      if (suggestions.size >= limit) break;
    }

    return Array.from(suggestions).slice(0, limit);
  }
}

/**
 * Phase 03 Unit Conversion
 *
 * Canonical millimetre conversion for the Open3D catalog system.
 * Handles the legacy naming debt: OOFPLWeb catalog stores dimensions as cm
 * in fields named `widthMm`/`heightMm` despite the misleading suffix.
 *
 * All internal geometry uses canonical millimetres.
 * Display values are derived via centralized converters based on user-selected unit.
 */

import type { Open3dCatalogDimensions } from "./catalogTypes";

// ── Conversion constants ──

const MM_PER_CM = 10;
const MM_PER_M = 1000;
const MM_PER_INCH = 25.4;

const CONFIGURATOR_HEIGHT_MM_THRESHOLD = 300;

// ── Core converters ──

/**
 * Convert legacy OOFPLWeb catalog fields (stored as cm despite "Mm" suffix)
 * to canonical millimetres.
 *
 * NAMING DEBT: The OOFPLWeb `widthMm` and `heightMm` fields actually contain
 * centimetre values. This converter corrects for that. The naming is preserved
 * in the bridge layer to avoid breaking existing API consumers.
 */
export function canonicalMmFromCatalogCm(value: number): number {
  return Math.max(1, Math.round(value * MM_PER_CM));
}

/**
 * Configurator payloads currently mix units:
 * - footprint L/D values are supplied in centimetres
 * - H / heightMm values are supplied in millimetres despite the mixed contract
 *
 * Some callers may already normalize height to centimetres before mapping. To
 * stay resilient without mutating upstream contracts, values above the practical
 * furniture-height threshold are treated as millimetres and converted to cm.
 */
export function configuratorHeightCmFromMixedUnit(
  value: number | undefined,
  fallbackCm = 75,
): number {
  if (!Number.isFinite(value) || value == null || value <= 0) {
    return fallbackCm;
  }

  if (value > CONFIGURATOR_HEIGHT_MM_THRESHOLD) {
    return value / MM_PER_CM;
  }

  return value;
}

/**
 * Build Open3dCatalogDimensions from legacy cm values.
 */
export function canonicalDimensionsFromCatalogCm(params: {
  widthCm: number;
  depthCm: number;
  heightCm?: number;
  seatHeightCm?: number;
  weightKg?: number;
}): Open3dCatalogDimensions {
  return {
    widthMm: canonicalMmFromCatalogCm(params.widthCm),
    depthMm: canonicalMmFromCatalogCm(params.depthCm),
    heightMm: canonicalMmFromCatalogCm(params.heightCm ?? 75),
    seatHeightMm: params.seatHeightCm != null ? canonicalMmFromCatalogCm(params.seatHeightCm) : undefined,
    weightKg: params.weightKg,
  };
}

/**
 * Convert canonical millimetres to display centimetres.
 */
export function displayCmFromCanonicalMm(mm: number): number {
  return Math.round(mm / MM_PER_CM);
}

/**
 * Convert canonical millimetres to display inches.
 */
export function displayInFromCanonicalMm(mm: number): number {
  return Math.round((mm / MM_PER_INCH) * 100) / 100;
}

/**
 * Convert canonical millimetres to display metres.
 */
export function displayMFromCanonicalMm(mm: number): number {
  return Math.round((mm / MM_PER_M) * 1000) / 1000;
}

/**
 * Convert canonical millimetres to feet-inches string.
 */
export function displayFtInFromCanonicalMm(mm: number): string {
  const totalInches = mm / MM_PER_INCH;
  const feet = Math.floor(totalInches / 12);
  const inches = Math.round(totalInches % 12);
  return `${feet}' ${inches}"`;
}

/**
 * Format dimensions for display in the user's preferred unit.
 */
export function displayDimensions(
  dimensions: Open3dCatalogDimensions,
  unit: "mm" | "cm" | "m" | "in" | "ft-in",
): string {
  const converters: Record<string, (v: number) => string> = {
    mm: (v) => `${Math.round(v)} mm`,
    cm: (v) => `${displayCmFromCanonicalMm(v)} cm`,
    m: (v) => `${displayMFromCanonicalMm(v)} m`,
    in: (v) => `${displayInFromCanonicalMm(v)} in`,
    "ft-in": displayFtInFromCanonicalMm,
  };

  const fmt = converters[unit] ?? ((v: number) => `${displayCmFromCanonicalMm(v)} cm`);
  const parts: string[] = [`${fmt(dimensions.widthMm)} × ${fmt(dimensions.depthMm)}`];
  if (dimensions.heightMm > 0) {
    parts.push(`× ${fmt(dimensions.heightMm)}`);
  }
  return parts.join(" ");
}

/**
 * Build an accessible name for a catalog item including dimensions.
 * Example: "Office Chair, 45 cm by 45 cm by 90 cm"
 */
export function buildAccessibleName(name: string, dimensions: Open3dCatalogDimensions): string {
  const w = displayCmFromCanonicalMm(dimensions.widthMm);
  const d = displayCmFromCanonicalMm(dimensions.depthMm);
  const h = displayCmFromCanonicalMm(dimensions.heightMm);
  return `${name}, ${w} cm by ${d} cm by ${h} cm`;
}

// ── Validation ──

/**
 * Validate that dimensions are positive and within reasonable bounds.
 */
export function validateDimensions(dimensions: Open3dCatalogDimensions): {
  valid: boolean;
  errors: string[];
} {
  const errors: string[] = [];
  if (!Number.isFinite(dimensions.widthMm) || dimensions.widthMm <= 0) {
    errors.push("widthMm must be a positive finite number");
  }
  if (!Number.isFinite(dimensions.depthMm) || dimensions.depthMm <= 0) {
    errors.push("depthMm must be a positive finite number");
  }
  if (!Number.isFinite(dimensions.heightMm) || dimensions.heightMm <= 0) {
    errors.push("heightMm must be a positive finite number");
  }
  if (dimensions.widthMm > 100000) {
    errors.push("widthMm exceeds maximum reasonable value (100000 mm)");
  }
  if (dimensions.depthMm > 100000) {
    errors.push("depthMm exceeds maximum reasonable value (100000 mm)");
  }
  if (dimensions.heightMm > 100000) {
    errors.push("heightMm exceeds maximum reasonable value (100000 mm)");
  }
  if (dimensions.weightKg != null && (!Number.isFinite(dimensions.weightKg) || dimensions.weightKg < 0)) {
    errors.push("weightKg must be a non-negative finite number");
  }
  return { valid: errors.length === 0, errors };
}

